mapper.select:
select id, tenant_id, template_code, template_name, template_type, biz_type, file_format_type, charset, target_charset, with_bom, line_separator, delimiter, quote_char, escape_char, record_length, header_rows, footer_rows, header_template, trailer_template, checksum_type, compress_type, encrypt_type, naming_rule, field_mappings, validation_rule_set, default_query_code, default_query_sql, query_param_schema, streaming_enabled, page_size, fetch_size, chunk_size, preview_masking_enabled, error_line_masking_enabled, log_masking_enabled, content_encryption_enabled, encryption_key_ref, download_requires_approval, masking_rule_set, load_target_ref, export_data_ref, enabled, version, description, created_by, updated_by, created_at, updated_at from batch.file_template_config where tenant_id = #{q.tenantId} and is_deleted = false
and ( template_code like concat('%', #{q.keyword}, '%') or template_name like concat('%', #{q.keyword}, '%') or template_type like concat('%', #{q.keyword}, '%') )
and template_code like concat('%', #{q.templateCode}, '%')
and template_name like concat('%', #{q.templateName}, '%')
and template_type = #{q.templateType}
and biz_type = #{q.bizType}
and enabled = #{q.enabled}
order by template_code asc, version desc
limit #{q.pageRequest.pageSize} offset (#{q.pageRequest.pageNo} - 1) * #{q.pageRequest.pageSize}

select count(1)
from batch.file_template_config
where tenant_id = #{q.tenantId}
and is_deleted = false

    and (
        template_code like concat('%', #{q.keyword}, '%')
        or template_name like concat('%', #{q.keyword}, '%')
        or template_type like concat('%', #{q.keyword}, '%')
    )


    and template_code like concat('%', #{q.templateCode}, '%')


    and template_name like concat('%', #{q.templateName}, '%')


    and template_type = #{q.templateType}


    and biz_type = #{q.bizType}


    and enabled = #{q.enabled}

select *
from batch.file_template_config
where tenant_id = #{tenantId}
  and template_code = #{templateCode}
  and version = #{version}
  and is_deleted = false
limit 1
